{"path": "src/distance.rs", "content": "use std::arch::x86_64::*;

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());

    #[cfg(target_arch = "x86_64")]
    unsafe {
        if is_x86_feature_detected!("avx512f") {
            return l2_distance_avx512(a, b);
        }
        if is_x86_feature_detected!("avx2") {
            return l2_distance_avx2(a, b);
        }
    }

    l2_distance_scalar(a, b)
}

#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let len = a.len();
    let mut sum0 = _mm512_setzero_ps();
    let mut sum1 = _mm512_setzero_ps();

    // Process 32 floats at a time (2 AVX-512 registers)
    let mut i = 0;
    while i + 32 <= len {
        let va0 = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb0 = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(diff0, diff0, sum0);

        let va1 = _mm512_loadu_ps(a.as_ptr().add(i + 16));
        let vb1 = _mm512_loadu_ps(b.as_ptr().add(i + 16));
        let diff1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(diff1, diff1, sum1);

        i += 32;
    }

    // Handle remaining 16 floats
    if i + 16 <= len {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        sum0 = _mm512_fmadd_ps(diff, diff, sum0);
        i += 16;
    }

    // Horizontal sum of both accumulators
    sum0 = _mm512_add_ps(sum0, sum1);
    let mut result = _mm512_reduce_add_ps(sum0) as f64;

    // Scalar cleanup for remaining elements
    while i < len {
        let diff = a[i] - b[i];
        result += (diff * diff) as f64;
        i += 1;
    }

    result
}

#[target_feature(enable = "avx2")]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let len = a.len();
    let mut sum0 = _mm256_setzero_ps();
    let mut sum1 = _mm256_setzero_ps();

    // Process 16 floats at a time (2 AVX2 registers)
    let mut i = 0;
    while i + 16 <= len {
        let va0 = _mm256_loadu_ps(a.as_ptr().add(i));
        let vb0 = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff0 = _mm256_sub_ps(va0, vb0);
        sum0 = _mm256_fmadd_ps(diff0, diff0, sum0);

        let va1 = _mm256_loadu_ps(a.as_ptr().add(i + 8));
        let vb1 = _mm256_loadu_ps(b.as_ptr().add(i + 8));
        let diff1 = _mm256_sub_ps(va1, vb1);
        sum1 = _mm256_fmadd_ps(diff1, diff1, sum1);

        i += 16;
    }

    sum0 = _mm256_add_ps(sum0, sum1);

    // Handle remaining 8 floats
    if i + 8 <= len {
        let va = _mm256_loadu_ps(a.as_ptr().add(i));
        let vb = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff = _mm256_sub_ps(va, vb);
        sum0 = _mm256_fmadd_ps(diff, diff, sum0);
        i += 8;
    }

    // Horizontal sum
    let mut result = hsum256_ps_avx(sum0) as f64;

    // Scalar cleanup
    while i < len {
        let diff = a[i] - b[i];
        result += (diff * diff) as f64;
        i += 1;
    }

    result
}

#[target_feature(enable = "avx2")]
unsafe fn hsum256_ps_avx(x: __m256) -> f32 {
    let x128 = _mm_add_ps(_mm256_extractf128_ps(x, 1), _mm256_castps256_ps128(x));
    let x64 = _mm_add_ps(x128, _mm_movehl_ps(x128, x128));
    let x32 = _mm_add_ss(x64, _mm_shuffle_ps(x64, x64, 0x55));
    _mm_cvtss_f32(x32)
}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let diff = *x - *y;
            (diff * diff) as f64
        })
        .sum()
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;

pub struct VectorDB {
    // Store vectors in a contiguous Vec for cache efficiency
    // Each vector is 128 f32s = 512 bytes
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::with_capacity(1_100_000)),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.vectors.write().unwrap();
        guard.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut guard = self.vectors.write().unwrap();
        let count = vectors.len();
        guard.reserve(vectors.len());
        for (id, vec) in vectors {
            guard.push((id, vec));
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let guard = self.vectors.read().unwrap();
        let vectors = &*guard;
        let top_k = top_k as usize;

        if vectors.is_empty() {
            return Vec::new();
        }

        // Parallel brute-force search using rayon
        // Each thread computes distances for a chunk and finds local top-k
        // Then we merge the results

        let num_threads = rayon::current_num_threads().min(4);
        let chunk_size = (vectors.len() + num_threads - 1) / num_threads;

        if chunk_size == 0 {
            // Fallback to sequential for small datasets
            return self.search_sequential(query, top_k, vectors);
        }

        // Split work into chunks and process in parallel
        let local_results: Vec<Vec<(u64, f64)>> = vectors
            .par_chunks(chunk_size)
            .map(|chunk| {
                let mut local_best: Vec<(u64, f64)> = Vec::with_capacity(top_k);

                for (id, vec) in chunk {
                    let dist = l2_distance(query, vec);

                    if local_best.len() < top_k {
                        local_best.push((*id, dist));
                        // Keep sorted
                        if local_best.len() == top_k {
                            local_best.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                        }
                    } else if dist < local_best[top_k - 1].1 {
                        local_best[top_k - 1] = (*id, dist);
                        // Re-sort
                        local_best.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                    }
                }

                local_best
            })
            .collect();

        // Merge local results into global top-k
        let mut global_best: Vec<(u64, f64)> = Vec::with_capacity(top_k * local_results.len());
        for local in local_results {
            global_best.extend(local);
        }

        // Sort and take top-k
        global_best.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        global_best.truncate(top_k);

        global_best
            .into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }

    fn search_sequential(
        &self,
        query: &[f32],
        top_k: usize,
        vectors: &[(u64, Vec<f32>)],
    ) -> Vec<SearchResult> {
        let mut best: Vec<(u64, f64)> = Vec::with_capacity(top_k);

        for (id, vec) in vectors {
            let dist = l2_distance(query, vec);

            if best.len() < top_k {
                best.push((*id, dist));
                if best.len() == top_k {
                    best.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                }
            } else if dist < best[top_k - 1].1 {
                best[top_k - 1] = (*id, dist);
                best.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
            }
        }

        best.into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Wrapper for binary heap that orders by distance (min-heap behavior)
#[derive(Clone, Copy)]
struct HeapItem {
    distance: f64,
    id: u64,
}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for HeapItem {}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Reverse order for max-heap behavior (we want to evict largest)
        other.distance.partial_cmp(&self.distance)
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        other.distance.partial_cmp(&self.distance).unwrap()
    }
}

pub struct VectorDB {
    // Contiguous storage: all vectors stored flat
    // ids[i] corresponds to data[i*128..(i+1)*128]
    ids: RwLock<Vec<u64>>,
    data: RwLock<Vec<f32>>, // Flattened: id 0 -> [0..128), id 1 -> [128..256), etc.
    dim: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            ids: RwLock::new(Vec::with_capacity(1_100_000)),
            data: RwLock::new(Vec::with_capacity(1_100_000 * 128)),
            dim: 128,
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids_guard = self.ids.write().unwrap();
        let mut data_guard = self.data.write().unwrap();

        ids_guard.push(id);
        data_guard.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids_guard = self.ids.write().unwrap();
        let mut data_guard = self.data.write().unwrap();

        let count = vectors.len();
        ids_guard.reserve(count);
        data_guard.reserve(count * self.dim);

        for (id, vec) in vectors {
            ids_guard.push(id);
            data_guard.extend_from_slice(&vec);
        }

        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids_guard = self.ids.read().unwrap();
        let data_guard = self.data.read().unwrap();

        let ids = &*ids_guard;
        let data = &*data_guard;
        let n = ids.len();
        let top_k = top_k as usize;

        if n == 0 {
            return Vec::new();
        }

        // Parallel search with binary heaps
        let num_threads = rayon::current_num_threads().min(4);
        let chunk_size = (n + num_threads - 1) / num_threads;

        if chunk_size < 100 {
            // Sequential for small datasets
            return self.search_sequential(query, top_k, ids, data);
        }

        // Process chunks in parallel, each producing a local top-k
        let local_results: Vec<Vec<HeapItem>> = (0..n)
            .into_par_iter()
            .chunks(chunk_size)
            .map(|chunk_indices| {
                let mut heap: BinaryHeap<HeapItem> = BinaryHeap::with_capacity(top_k + 1);

                for idx in chunk_indices {
                    let start = idx * self.dim;
                    let vector = &data[start..start + self.dim];
                    let dist = l2_distance(query, vector);

                    if heap.len() < top_k {
                        heap.push(HeapItem { distance: dist, id: ids[idx] });
                    } else if dist < heap.peek().unwrap().distance {
                        heap.pop();
                        heap.push(HeapItem { distance: dist, id: ids[idx] });
                    }
                }

                heap.into_vec()
            })
            .collect();

        // Merge local results into final top-k
        let mut final_heap: BinaryHeap<HeapItem> = BinaryHeap::with_capacity(top_k + 1);
        for local in local_results {
            for item in local {
                if final_heap.len() < top_k {
                    final_heap.push(item);
                } else if item.distance < final_heap.peek().unwrap().distance {
                    final_heap.pop();
                    final_heap.push(item);
                }
            }
        }

        // Convert to sorted result (ascending by distance)
        let mut results: Vec<HeapItem> = final_heap.into_vec();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
            .into_iter()
            .take(top_k)
            .map(|item| SearchResult { id: item.id, distance: item.distance })
            .collect()
    }

    fn search_sequential(
        &self,
        query: &[f32],
        top_k: usize,
        ids: &[u64],
        data: &[f32],
    ) -> Vec<SearchResult> {
        let n = ids.len();
        let mut heap: BinaryHeap<HeapItem> = BinaryHeap::with_capacity(top_k + 1);

        for i in 0..n {
            let start = i * self.dim;
            let vector = &data[start..start + self.dim];
            let dist = l2_distance(query, vector);

            if heap.len() < top_k {
                heap.push(HeapItem { distance: dist, id: ids[i] });
            } else if dist < heap.peek().unwrap().distance {
                heap.pop();
                heap.push(HeapItem { distance: dist, id: ids[i] });
            }
        }

        // Convert to sorted result
        let mut results: Vec<HeapItem> = heap.into_vec();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
            .into_iter()
            .take(top_k)
            .map(|item| SearchResult { id: item.id, distance: item.distance })
            .collect()
    }
}
"}

